#include <stdio.h>
#include <math.h>

// Function to calculate the Euclidean distance
float euclidean_distance(float *input_image, float *prototype, int n) {
  float sum = 0;
  for (int i = 0; i < n; i++) {
    sum += pow(input_image[i] - prototype[i], 2);
  }
  return sqrt(sum);
}

// Function to find the index of the minimum distance
int arg_min(float *distances, int n) {
  int min_index = 0;
  float min_distance = distances[0];
  for (int i = 1; i < n; i++) {
    if (distances[i] < min_distance) {
      min_distance = distances[i];
      min_index = i;
    }
  }
  return min_index;
}

int main() {
  // Load the dataset
  float X_train[100][10];
  int y_train[100];

  // Preprocess the input image
  float input_image[10];

  // Calculate the distance between the input image and each prototype
  float distances[100];
  for (int i = 0; i < 100; i++) {
    distances[i] = euclidean_distance(input_image, X_train[i], 10);
  }

  // Find the index of the minimum distance
  int min_distance_index = arg_min(distances, 100);

  // Assign the class label based on the minimum distance
  int class_label = y_train[min_distance_index];
  printf("%d\n", class_label);
  return 0;
}
